20	function assertDamagesValid(
21	  policyItems: { type: string }[],
22	  damages: { itemType: string; amount: number }[],
23	): void {
24	  const policyItemTypes = policyItems.map((item) => item.type);
25	  const damageCounts = new Map<string, number>();
26	  for (const damage of damages) {
27	    if (!policyItemTypes.includes(damage.itemType)) {
28	      throw new Error(
29	        `Claim damages an item not in policy: ${damage.itemType}`,
30	      );
31	    }
32	    if (damage.amount < 0) {
33	      throw new Error(`Negative damage amount: ${damage.amount}`);
34	    }
35	    damageCounts.set(
36	      damage.itemType,
37	      (damageCounts.get(damage.itemType) ?? 0) + 1,
38	    );
39	  }
40	  for (const [itemType, count] of damageCounts) {
41	    const coverageCount = policyItemTypes.filter(
42	      (type) => type === itemType,
43	    ).length;
44	    if (count > coverageCount) {
45	      throw new Error(`Too many damages for item type: ${itemType}`);
46	    }
