50	export function runScenario(scenario: any): { results: unknown[] } {
51	  const results: unknown[] = [];
52	  let quoteCount = 0;
53	  const remainingCaps = new Map<number, number>();
54	  for (const step of scenario.steps) {
55	    if (step.op === "quote") {
56	      assertKnownItemTypes(step.items);
57	      const premium = quote({
58	        customer: {
59	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
60	          previousContracts: quoteCount,
61	        },
62	        items: step.items,
63	      });
64	      results.push({ premium });
65	      quoteCount++;
66	    } else if (step.op === "claim") {
67	      const policyStep = scenario.steps[step.policy];
68	      assertDamagesValid(policyStep.items, step.incident.damages);
69	      const { payout, remainingCap } = claim({
70	        items: policyStep.items,
71	        incident: step.incident,
72	        remainingCap: remainingCaps.get(step.policy),
73	      });
74	      remainingCaps.set(step.policy, remainingCap);
75	      results.push({ payout, remainingCap });
76	    }
77	  }
78	  return { results };
79	}
